var canBeEqual = function(s1, s2) {
    const evens1 = [s1[0], s1[2]].sort();
    const evens2 = [s2[0], s2[2]].sort();
    const odds1 = [s1[1], s1[3]].sort();
    const odds2 = [s2[1], s2[3]].sort();
    return evens1[0] === evens2[0] && evens1[1] === evens2[1] && odds1[0] === odds2[0] && odds1[1] === odds2[1];
};
